     1→// ============================================================================
     2→// MIRRORBUDDY - MAIN APPLICATION STORE (Zustand)
     3→// With database sync via API routes
     4→// ============================================================================
     5→
     6→import { create } from 'zustand';
     7→import { logger } from '@/lib/logger';
     8→import { onLevelUp, onStreakMilestone, onAchievement } from '@/lib/notifications/triggers';
     9→import type {
    10→  Maestro,
    11→  Theme,
    12→  AIProvider,
    13→  Streak,
    14→  Achievement,
    15→  SubjectMastery,
    16→  Conversation,
    17→  ChatMessage,
    18→  ToolCall,
    19→} from '@/types';
    20→import type { ToolState, ToolType } from '@/types/tools';
    21→import { XP_PER_LEVEL } from '@/lib/constants/xp-rewards';
    22→
    23→// === SETTINGS STORE ===
    24→
    25→interface AppearanceSettings {
    26→  theme: 'light' | 'dark' | 'system';
    27→  accentColor: string;
    28→  language: 'it' | 'en' | 'es' | 'fr' | 'de';
    29→}
    30→
    31→// Teaching style from super encouraging to brutal
    32→export type TeachingStyle = 'super_encouraging' | 'encouraging' | 'balanced' | 'strict' | 'brutal';
    33→
    34→/**
    35→ * Learning differences that the platform supports.
    36→ * Used for buddy matching and accessibility features.
    37→ */
    38→export type LearningDifference =
    39→  | 'dyslexia'
    40→  | 'dyscalculia'
    41→  | 'dysgraphia'
    42→  | 'adhd'
    43→  | 'autism'
    44→  | 'cerebralPalsy'
    45→  | 'visualImpairment'
    46→  | 'auditoryProcessing';
    47→
    48→interface ExtendedStudentProfile {
    49→  name: string;
    50→  age: number;
    51→  schoolYear: number;
    52→  schoolLevel: 'elementare' | 'media' | 'superiore';
    53→  gradeLevel: string;
    54→  learningGoals: string[];
    55→  teachingStyle: TeachingStyle;
    56→  fontSize: 'small' | 'medium' | 'large' | 'extra-large';
    57→  highContrast: boolean;
    58→  dyslexiaFont: boolean;
    59→  voiceEnabled: boolean;
    60→  simplifiedLanguage: boolean;
    61→  adhdMode: boolean;
    62→  // MirrorBuddy character preferences
    63→  learningDifferences: LearningDifference[];
    64→  preferredCoach?: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
    65→  preferredBuddy?: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
    66→  // Custom border colors for coach and buddy avatars
    67→  coachBorderColor?: string;
    68→  buddyBorderColor?: string;
    69→}
    70→
    71→// Provider preference for manual selection
    72→export type ProviderPreference = 'azure' | 'ollama' | 'auto';
    73→
    74→interface SettingsState {
    75→  theme: Theme;
    76→  provider: AIProvider;
    77→  model: string;
    78→  budgetLimit: number;
    79→  totalSpent: number;
    80→  studentProfile: ExtendedStudentProfile;
    81→  appearance: AppearanceSettings;
    82→  preferredProvider: ProviderPreference;
    83→  preferredMicrophoneId: string; // Empty string = system default
    84→  preferredOutputId: string; // Empty string = system default (speakers)
    85→  preferredCameraId: string; // Empty string = system default
    86→  // Voice settings (Azure Realtime API)
    87→  voiceVadThreshold: number; // VAD sensitivity (0.3-0.7, default 0.4)
    88→  voiceSilenceDuration: number; // Silence before turn ends (300-800ms, default 400)
    89→  voiceBargeInEnabled: boolean; // Allow interrupting maestro (default true)
    90→  // Sync state
    91→  lastSyncedAt: Date | null;
    92→  pendingSync: boolean;
    93→  // Actions
    94→  setTheme: (theme: Theme) => void;
    95→  setProvider: (provider: AIProvider) => void;
    96→  setModel: (model: string) => void;
    97→  setBudgetLimit: (limit: number) => void;
    98→  addCost: (cost: number) => void;
    99→  updateStudentProfile: (profile: Partial<ExtendedStudentProfile>) => void;
   100→  updateAppearance: (appearance: Partial<AppearanceSettings>) => void;
   101→  setPreferredProvider: (provider: ProviderPreference) => void;
   102→  setPreferredMicrophone: (microphoneId: string) => void;
   103→  setPreferredOutput: (outputId: string) => void;
   104→  setPreferredCamera: (cameraId: string) => void;
   105→  // Voice settings actions
   106→  setVoiceVadThreshold: (threshold: number) => void;
   107→  setVoiceSilenceDuration: (duration: number) => void;
   108→  setVoiceBargeInEnabled: (enabled: boolean) => void;
   109→  // Sync actions
   110→  syncToServer: () => Promise<void>;
   111→  loadFromServer: () => Promise<void>;
   112→}
   113→
   114→export const useSettingsStore = create<SettingsState>()(
   115→  (set, get) => ({
   116→      theme: 'system',
   117→      provider: 'azure',  // #89: Changed from 'openai' - only azure/ollama supported
   118→      model: 'gpt-4o',
   119→      budgetLimit: 50,
   120→      totalSpent: 0,
   121→      studentProfile: {
   122→        name: '',
   123→        age: 14,
   124→        schoolYear: 1,
   125→        schoolLevel: 'superiore',
   126→        gradeLevel: '',
   127→        learningGoals: [],
   128→        teachingStyle: 'balanced',
   129→        fontSize: 'medium',
   130→        highContrast: false,
   131→        dyslexiaFont: false,
   132→        voiceEnabled: true,
   133→        simplifiedLanguage: false,
   134→        adhdMode: false,
   135→        // MirrorBuddy defaults
   136→        learningDifferences: [],
   137→        preferredCoach: undefined,
   138→        preferredBuddy: undefined,
   139→      },
   140→      appearance: {
   141→        theme: 'system',
   142→        accentColor: 'blue',
   143→        language: 'it',
   144→      },
   145→      preferredProvider: 'auto',
   146→      preferredMicrophoneId: '', // Empty = system default
   147→      preferredOutputId: '', // Empty = system default (speakers)
   148→      preferredCameraId: '', // Empty = system default
   149→      // Voice settings defaults
   150→      voiceVadThreshold: 0.4, // Balanced sensitivity
   151→      voiceSilenceDuration: 400, // Fast turn-taking
   152→      voiceBargeInEnabled: true, // Allow interrupting maestro
   153→      lastSyncedAt: null,
   154→      pendingSync: false,
   155→
   156→      setTheme: (theme) => set({ theme, pendingSync: true }),
   157→      setProvider: (provider) => set({ provider, pendingSync: true }),
   158→      setModel: (model) => set({ model, pendingSync: true }),
   159→      setBudgetLimit: (budgetLimit) => set({ budgetLimit, pendingSync: true }),
   160→      addCost: (cost) =>
   161→        set((state) => ({ totalSpent: state.totalSpent + cost, pendingSync: true })),
   162→      updateStudentProfile: (profile) =>
   163→        set((state) => ({
   164→          studentProfile: { ...state.studentProfile, ...profile },
   165→          pendingSync: true,
   166→        })),
   167→      updateAppearance: (appearance) =>
   168→        set((state) => ({
   169→          appearance: { ...state.appearance, ...appearance },
   170→          pendingSync: true,
   171→        })),
   172→      setPreferredProvider: (preferredProvider) =>
   173→        set({ preferredProvider, pendingSync: true }),
   174→      setPreferredMicrophone: (preferredMicrophoneId) =>
   175→        set({ preferredMicrophoneId, pendingSync: true }),
   176→      setPreferredOutput: (preferredOutputId) =>
   177→        set({ preferredOutputId, pendingSync: true }),
   178→      setPreferredCamera: (preferredCameraId) =>
   179→        set({ preferredCameraId, pendingSync: true }),
   180→      // Voice settings setters with validation
   181→      setVoiceVadThreshold: (threshold) =>
   182→        set({ voiceVadThreshold: Math.max(0.3, Math.min(0.7, threshold)), pendingSync: true }),
   183→      setVoiceSilenceDuration: (duration) =>
   184→        set({ voiceSilenceDuration: Math.max(300, Math.min(800, duration)), pendingSync: true }),
   185→      setVoiceBargeInEnabled: (enabled) =>
   186→        set({ voiceBargeInEnabled: enabled, pendingSync: true }),
   187→
   188→      syncToServer: async () => {
   189→        const state = get();
   190→        if (!state.pendingSync) return;
   191→
   192→        try {
   193→          // Sync settings - #88: Added totalSpent to persist budget tracking
   194→          await fetch('/api/user/settings', {
   195→            method: 'PUT',
   196→            headers: { 'Content-Type': 'application/json' },
   197→            body: JSON.stringify({
   198→              theme: state.theme,
   199→              provider: state.provider,
   200→              model: state.model,
   201→              budgetLimit: state.budgetLimit,
   202→              totalSpent: state.totalSpent,  // #88: Now persisted
   203→              language: state.appearance.language,
   204→              accentColor: state.appearance.accentColor,
   205→            }),
   206→          });
   207→
   208→          // Sync profile
   209→          await fetch('/api/user/profile', {
   210→            method: 'PUT',
   211→            headers: { 'Content-Type': 'application/json' },
   212→            body: JSON.stringify({
   213→              name: state.studentProfile.name,
   214→              age: state.studentProfile.age,
   215→              schoolYear: state.studentProfile.schoolYear,
   216→              schoolLevel: state.studentProfile.schoolLevel,
   217→              gradeLevel: state.studentProfile.gradeLevel,
   218→              learningGoals: state.studentProfile.learningGoals,
   219→              // Character preferences
   220→              preferredCoach: state.studentProfile.preferredCoach,
   221→              preferredBuddy: state.studentProfile.preferredBuddy,
   222→              accessibility: {
   223→                fontSize: state.studentProfile.fontSize,
   224→                highContrast: state.studentProfile.highContrast,
   225→                dyslexiaFont: state.studentProfile.dyslexiaFont,
   226→                voiceEnabled: state.studentProfile.voiceEnabled,
   227→                simplifiedLanguage: state.studentProfile.simplifiedLanguage,
   228→                adhdMode: state.studentProfile.adhdMode,
   229→              },
   230→            }),
   231→          });
   232→
   233→          set({ lastSyncedAt: new Date(), pendingSync: false });
   234→        } catch (error) {
   235→          logger.error('Settings sync failed', { error: String(error) });
   236→        }
   237→      },
   238→
   239→      loadFromServer: async () => {
   240→        try {
   241→          const [settingsRes, profileRes] = await Promise.all([
   242→            fetch('/api/user/settings'),
   243→            fetch('/api/user/profile'),
   244→          ]);
   245→
   246→          if (settingsRes.ok) {
   247→            const settings = await settingsRes.json();
   248→            set((state) => ({
   249→              theme: settings.theme ?? state.theme,
   250→              provider: settings.provider ?? state.provider,
   251→              model: settings.model ?? state.model,
   252→              budgetLimit: settings.budgetLimit ?? state.budgetLimit,
   253→              totalSpent: settings.totalSpent ?? state.totalSpent,  // #88: Load from server
   254→              appearance: {
   255→                ...state.appearance,
   256→                language: settings.language ?? state.appearance.language,
   257→                accentColor: settings.accentColor ?? state.appearance.accentColor,
   258→              },
   259→            }));
   260→          }
   261→
   262→          if (profileRes.ok) {
   263→            const profile = await profileRes.json();
   264→            if (profile) {
   265→              const accessibility = profile.accessibility || {};
   266→              set((state) => ({
   267→                studentProfile: {
   268→                  ...state.studentProfile,
   269→                  name: profile.name ?? state.studentProfile.name,
   270→                  age: profile.age ?? state.studentProfile.age,
   271→                  schoolYear: profile.schoolYear ?? state.studentProfile.schoolYear,
   272→                  schoolLevel: profile.schoolLevel ?? state.studentProfile.schoolLevel,
   273→                  gradeLevel: profile.gradeLevel ?? state.studentProfile.gradeLevel,
   274→                  learningGoals: profile.learningGoals ?? state.studentProfile.learningGoals,
   275→                  // Character preferences
   276→                  preferredCoach: profile.preferredCoach ?? state.studentProfile.preferredCoach,
   277→                  preferredBuddy: profile.preferredBuddy ?? state.studentProfile.preferredBuddy,
   278→                  fontSize: accessibility.fontSize ?? state.studentProfile.fontSize,
   279→                  highContrast: accessibility.highContrast ?? state.studentProfile.highContrast,
   280→                  dyslexiaFont: accessibility.dyslexiaFont ?? state.studentProfile.dyslexiaFont,
   281→                  voiceEnabled: accessibility.voiceEnabled ?? state.studentProfile.voiceEnabled,
   282→                  simplifiedLanguage: accessibility.simplifiedLanguage ?? state.studentProfile.simplifiedLanguage,
   283→                  adhdMode: accessibility.adhdMode ?? state.studentProfile.adhdMode,
   284→                },
   285→              }));
   286→            }
   287→          }
   288→
   289→          set({ lastSyncedAt: new Date(), pendingSync: false });
   290→        } catch (error) {
   291→          logger.error('Settings load failed', { error: String(error) });
   292→        }
   293→      },
   294→    })
   295→);
   296→
   297→// === PROGRESS STORE (Gamification) ===
   298→
   299→// Session grade given by maestro (1-10 scale)
   300→export interface SessionGrade {
   301→  score: number; // 1-10
   302→  feedback: string;
   303→  strengths: string[];
   304→  areasToImprove: string[];
   305→}
   306→
   307→interface StudySession {
   308→  id: string;
   309→  maestroId: string;
   310→  subject: string;
   311→  startedAt: Date;
   312→  endedAt?: Date;
   313→  durationMinutes?: number;
   314→  questionsAsked: number;
   315→  xpEarned: number;
   316→  grade?: SessionGrade; // Grade given by maestro at end of session
   317→}
   318→
   319→interface ProgressState {
   320→  xp: number;
   321→  level: number;
   322→  streak: Streak;
   323→  masteries: SubjectMastery[];
   324→  achievements: Achievement[];
   325→  totalStudyMinutes: number;
   326→  sessionsThisWeek: number;
   327→  questionsAsked: number;
   328→  // Session tracking
   329→  currentSession: StudySession | null;
   330→  sessionHistory: StudySession[];
   331→  // Sync state
   332→  lastSyncedAt: Date | null;
   333→  pendingSync: boolean;
   334→  // Actions
   335→  addXP: (amount: number) => void;
   336→  updateStreak: () => void;
   337→  updateMastery: (subjectMastery: SubjectMastery) => void;
   338→  unlockAchievement: (achievementId: string) => void;
   339→  addStudyMinutes: (minutes: number) => void;
   340→  incrementQuestions: () => void;
   341→  // Session actions
   342→  startSession: (maestroId: string, subject: string) => void;
   343→  endSession: (grade?: SessionGrade) => void;
   344→  gradeCurrentSession: (grade: SessionGrade) => void;
   345→  // Sync actions
   346→  syncToServer: () => Promise<void>;
   347→  loadFromServer: () => Promise<void>;
   348→}
   349→
   350→export const useProgressStore = create<ProgressState>()(
   351→  (set, get) => ({
   352→      xp: 0,
   353→      level: 1,
   354→      streak: { current: 0, longest: 0 },
   355→      masteries: [],
   356→      achievements: [],
   357→      totalStudyMinutes: 0,
   358→      sessionsThisWeek: 0,
   359→      questionsAsked: 0,
   360→      currentSession: null,
   361→      sessionHistory: [],
   362→      lastSyncedAt: null,
   363→      pendingSync: false,
   364→
   365→      addXP: (amount) =>
   366→        set((state) => {
   367→          const newXP = state.xp + amount;
   368→          let newLevel = state.level;
   369→          while (
   370→            newLevel < XP_PER_LEVEL.length - 1 &&
   371→            newXP >= XP_PER_LEVEL[newLevel]
   372→          ) {
   373→            newLevel++;
   374→          }
   375→          // Trigger level up notification if level increased
   376→          if (newLevel > state.level) {
   377→            const levelTitles: Record<number, string> = {
   378→              1: 'Principiante',
   379→              2: 'Apprendista',
   380→              3: 'Studente',
   381→              4: 'Studioso',
   382→              5: 'Esperto',
   383→              6: 'Professore',
   384→              7: 'Gran Professore',
   385→              8: 'Saggio',
   386→              9: 'Illuminato',
   387→              10: 'Leggenda',
   388→            };
   389→            onLevelUp(newLevel, levelTitles[newLevel] || `Livello ${newLevel}`);
   390→          } else if (amount > 0) {
   391→            // Show XP toast notification (only if not leveling up to avoid duplicate notifications)
   392→            // Import toast dynamically to avoid circular dependencies
   393→            import('@/components/ui/toast').then(({ default: toast }) => {
   394→              toast.success(`+${amount} XP`, `Totale: ${newXP} XP`, { duration: 3000 });
   395→            }).catch((err) => {
   396→              logger.warn('Failed to show XP toast', { error: err });
   397→            });
   398→          }
   399→          // Update current session XP
   400→          const updatedSession = state.currentSession
   401→            ? { ...state.currentSession, xpEarned: state.currentSession.xpEarned + amount }
   402→            : null;
   403→          return { xp: newXP, level: newLevel, currentSession: updatedSession, pendingSync: true };
   404→        }),
   405→
   406→      updateStreak: () =>
   407→        set((state) => {
   408→          const today = new Date().toDateString();
   409→          const lastStudy = state.streak.lastStudyDate;
   410→          const yesterday = new Date(Date.now() - 86400000).toDateString();
   411→
   412→          let newCurrent = state.streak.current;
   413→          if (!lastStudy || new Date(lastStudy).toDateString() !== today) {
   414→            if (lastStudy && new Date(lastStudy).toDateString() === yesterday) {
   415→              newCurrent++;
   416→            } else if (!lastStudy || new Date(lastStudy).toDateString() !== yesterday) {
   417→              newCurrent = 1;
   418→            }
   419→          }
   420→
   421→          // Trigger streak milestone notification if applicable
   422→          if (newCurrent > state.streak.current) {
   423→            onStreakMilestone(newCurrent);
   424→          }
   425→
   426→          return {
   427→            streak: {
   428→              current: newCurrent,
   429→              longest: Math.max(state.streak.longest, newCurrent),
   430→              lastStudyDate: new Date(),
   431→            },
   432→            pendingSync: true,
   433→          };
   434→        }),
   435→
   436→      updateMastery: (subjectMastery) =>
   437→        set((state) => {
   438→          const existing = state.masteries.findIndex(
   439→            (m) => m.subject === subjectMastery.subject
   440→          );
   441→          if (existing >= 0) {
   442→            const newMasteries = [...state.masteries];
   443→            newMasteries[existing] = subjectMastery;
   444→            return { masteries: newMasteries, pendingSync: true };
   445→          }
   446→          return { masteries: [...state.masteries, subjectMastery], pendingSync: true };
   447→        }),
   448→
   449→      unlockAchievement: (achievementId) =>
   450→        set((state) => {
   451→          const achievement = state.achievements.find(
   452→            (a) => a.id === achievementId
   453→          );
   454→          if (achievement && !achievement.unlockedAt) {
   455→            // Trigger achievement notification
   456→            onAchievement(achievement.name, achievement.description);
   457→            return {
   458→              achievements: state.achievements.map((a) =>
   459→                a.id === achievementId ? { ...a, unlockedAt: new Date() } : a
   460→              ),
   461→              pendingSync: true,
   462→            };
   463→          }
   464→          return state;
   465→        }),
   466→
   467→      addStudyMinutes: (minutes) =>
   468→        set((state) => ({
   469→          totalStudyMinutes: state.totalStudyMinutes + minutes,
   470→          pendingSync: true,
   471→        })),
   472→
   473→      incrementQuestions: () =>
   474→        set((state) => {
   475→          const updatedSession = state.currentSession
   476→            ? { ...state.currentSession, questionsAsked: state.currentSession.questionsAsked + 1 }
   477→            : null;
   478→          return {
   479→            questionsAsked: state.questionsAsked + 1,
   480→            currentSession: updatedSession,
   481→            pendingSync: true,
   482→          };
   483→        }),
   484→
   485→      startSession: (maestroId, subject) =>
   486→        set((state) => {
   487→          // End any existing session first
   488→          if (state.currentSession) {
   489→            const endedSession = {
   490→              ...state.currentSession,
   491→              endedAt: new Date(),
   492→              durationMinutes: Math.round(
   493→                (Date.now() - new Date(state.currentSession.startedAt).getTime()) / 60000
   494→              ),
   495→            };
   496→            return {
   497→              currentSession: {
   498→                id: crypto.randomUUID(),
   499→                maestroId,
   500→                subject,
   501→                startedAt: new Date(),
   502→                questionsAsked: 0,
   503→                xpEarned: 0,
   504→              },
   505→              sessionHistory: [endedSession, ...state.sessionHistory].slice(0, 100),
   506→              pendingSync: true,
   507→            };
   508→          }
   509→          return {
   510→            currentSession: {
   511→              id: crypto.randomUUID(),
   512→              maestroId,
   513→              subject,
   514→              startedAt: new Date(),
   515→              questionsAsked: 0,
   516→              xpEarned: 0,
   517→            },
   518→            pendingSync: true,
   519→          };
   520→        }),
   521→
   522→      endSession: (grade) =>
   523→        set((state) => {
   524→          if (!state.currentSession) return state;
   525→
   526→          const durationMinutes = Math.round(
   527→            (Date.now() - new Date(state.currentSession.startedAt).getTime()) / 60000
   528→          );
   529→          const endedSession = {
   530→            ...state.currentSession,
   531→            endedAt: new Date(),
   532→            durationMinutes,
   533→            grade: grade || state.currentSession.grade,
   534→          };
   535→
   536→          // Calculate week sessions
   537→          const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
   538→          const recentSessions = [endedSession, ...state.sessionHistory].filter(
   539→            (s) => new Date(s.startedAt) > weekAgo
   540→          );
   541→
   542→          return {
   543→            currentSession: null,
   544→            sessionHistory: [endedSession, ...state.sessionHistory].slice(0, 100),
   545→            totalStudyMinutes: state.totalStudyMinutes + durationMinutes,
   546→            sessionsThisWeek: recentSessions.length,
   547→            pendingSync: true,
   548→          };
   549→        }),
   550→
   551→      gradeCurrentSession: (grade) =>
   552→        set((state) => {
   553→          if (!state.currentSession) return state;
   554→          return {
   555→            currentSession: { ...state.currentSession, grade },
   556→            pendingSync: true,
   557→          };
   558→        }),
   559→
   560→      syncToServer: async () => {
   561→        const state = get();
   562→        if (!state.pendingSync) return;
   563→
   564→        try {
   565→          // Sync main progress
   566→          await fetch('/api/progress', {
   567→            method: 'PUT',
   568→            headers: { 'Content-Type': 'application/json' },
   569→            body: JSON.stringify({
   570→              xp: state.xp,
   571→              level: state.level,
   572→              streak: state.streak,
   573→              totalStudyMinutes: state.totalStudyMinutes,
   574→              questionsAsked: state.questionsAsked,
   575→              masteries: state.masteries,
   576→              achievements: state.achievements,
   577→            }),
   578→          });
   579→
   580→          // Sync recent sessions
   581→          const unsyncedSessions = state.sessionHistory.filter(
   582→            (s) => s.endedAt && !s.id.startsWith('synced-')
   583→          ).slice(0, 10);
   584→
   585→          for (const session of unsyncedSessions) {
   586→            await fetch('/api/progress/sessions', {
   587→              method: 'POST',
   588→              headers: { 'Content-Type': 'application/json' },
   589→              body: JSON.stringify(session),
   590→            });
   591→          }
   592→
   593→          set({ lastSyncedAt: new Date(), pendingSync: false });
   594→        } catch (error) {
   595→          logger.error('Progress sync failed', { error: String(error) });
   596→        }
   597→      },
   598→
   599→      loadFromServer: async () => {
   600→        try {
   601→          const [progressRes, sessionsRes] = await Promise.all([
   602→            fetch('/api/progress'),
   603→            fetch('/api/progress/sessions?limit=20'),
   604→          ]);
   605→
   606→          if (progressRes.ok) {
   607→            const data = await progressRes.json();
   608→            set((state) => ({
   609→              xp: data.xp ?? state.xp,
   610→              level: data.level ?? state.level,
   611→              streak: data.streak ?? state.streak,
   612→              masteries: data.masteries ?? state.masteries,
   613→              achievements: data.achievements ?? state.achievements,
   614→              totalStudyMinutes: data.totalStudyMinutes ?? state.totalStudyMinutes,
   615→              questionsAsked: data.questionsAsked ?? state.questionsAsked,
   616→            }));
   617→          }
   618→
   619→          if (sessionsRes.ok) {
   620→            const sessions = await sessionsRes.json();
   621→            if (Array.isArray(sessions)) {
   622→              // Calculate sessionsThisWeek from DB sessions
   623→              const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
   624→              const recentCount = sessions.filter(
   625→                (s: StudySession) => new Date(s.startedAt) > weekAgo
   626→              ).length;
   627→
   628→              set({
   629→                sessionHistory: sessions.map((s: StudySession) => ({
   630→                  ...s,
   631→                  id: `synced-${s.id}`, // Mark as synced
   632→                  startedAt: new Date(s.startedAt),
   633→                  endedAt: s.endedAt ? new Date(s.endedAt) : undefined,
   634→                })),
   635→                sessionsThisWeek: recentCount,
   636→              });
   637→            }
   638→          }
   639→
   640→          set({ lastSyncedAt: new Date(), pendingSync: false });
   641→        } catch (error) {
   642→          logger.error('Progress load failed', { error: String(error) });
   643→        }
   644→      },
   645→    })
   646→);
