   725→
   726→interface ConversationState {
   727→  conversations: Conversation[];
   728→  currentConversationId: string | null;
   729→  // Sync state
   730→  lastSyncedAt: Date | null;
   731→  pendingSync: boolean;
   732→  // Actions
   733→  createConversation: (maestroId?: string) => Promise<string>;
   734→  addMessage: (conversationId: string, message: Omit<ChatMessage, 'id' | 'timestamp'>) => Promise<void>;
   735→  setCurrentConversation: (id: string | null) => void;
   736→  deleteConversation: (id: string) => Promise<void>;
   737→  clearConversations: () => void;
   738→  // Sync actions
   739→  syncToServer: () => Promise<void>;
   740→  loadFromServer: () => Promise<void>;
   741→}
   742→
   743→export const useConversationStore = create<ConversationState>()(
   744→  (set) => ({
   745→      conversations: [],
   746→      currentConversationId: null,
   747→      lastSyncedAt: null,
   748→      pendingSync: false,
   749→
   750→      createConversation: async (maestroId) => {
   751→        const tempId = crypto.randomUUID();
   752→        const conversation: Conversation = {
   753→          id: tempId,
   754→          title: 'New Conversation',
   755→          messages: [],
   756→          maestroId,
   757→          createdAt: new Date(),
   758→          updatedAt: new Date(),
   759→        };
   760→
   761→        // Optimistic update
   762→        set((state) => ({
   763→          conversations: [conversation, ...state.conversations],
   764→          currentConversationId: tempId,
   765→        }));
   766→
   767→        // Sync to server
   768→        try {
   769→          const response = await fetch('/api/conversations', {
   770→            method: 'POST',
   771→            headers: { 'Content-Type': 'application/json' },
   772→            body: JSON.stringify({ maestroId }),
   773→          });
   774→
   775→          if (response.ok) {
   776→            const serverConv = await response.json();
   777→            // Update with server ID
   778→            set((state) => ({
   779→              conversations: state.conversations.map((c) =>
   780→                c.id === tempId ? { ...c, id: serverConv.id } : c
   781→              ),
   782→              currentConversationId:
   783→                state.currentConversationId === tempId
   784→                  ? serverConv.id
   785→                  : state.currentConversationId,
   786→            }));
   787→            return serverConv.id;
   788→          }
   789→        } catch (error) {
   790→          logger.error('Failed to create conversation on server', { error: String(error) });
   791→        }
   792→
   793→        return tempId;
   794→      },
   795→
   796→      addMessage: async (conversationId, message) => {
   797→        const messageWithId = {
   798→          ...message,
   799→          id: crypto.randomUUID(),
   800→          timestamp: new Date(),
   801→        };
   802→
   803→        // Optimistic update
   804→        set((state) => ({
   805→          conversations: state.conversations.map((conv) =>
   806→            conv.id === conversationId
   807→              ? {
   808→                  ...conv,
   809→                  messages: [...conv.messages, messageWithId],
   810→                  updatedAt: new Date(),
   811→                  title:
   812→                    conv.messages.length === 0 && message.role === 'user'
   813→                      ? message.content.slice(0, 50)
   814→                      : conv.title,
   815→                }
   816→              : conv
   817→          ),
   818→          pendingSync: true,
   819→        }));
   820→
   821→        // Sync to server
   822→        try {
   823→          await fetch(`/api/conversations/${conversationId}/messages`, {
   824→            method: 'POST',
   825→            headers: { 'Content-Type': 'application/json' },
   826→            body: JSON.stringify({
   827→              role: message.role,
   828→              content: message.content,
   829→              toolCalls: (message as { toolCalls?: unknown }).toolCalls,
   830→            }),
   831→          });
   832→        } catch (error) {
   833→          logger.error('Failed to add message to server', { error: String(error) });
   834→        }
   835→      },
   836→
   837→      setCurrentConversation: (id) => set({ currentConversationId: id }),
   838→
   839→      deleteConversation: async (id) => {
   840→        // Optimistic update
   841→        set((state) => ({
   842→          conversations: state.conversations.filter((c) => c.id !== id),
   843→          currentConversationId:
   844→            state.currentConversationId === id
   845→              ? null
   846→              : state.currentConversationId,
   847→        }));
   848→
   849→        // Sync to server
   850→        try {
   851→          await fetch(`/api/conversations/${id}`, { method: 'DELETE' });
   852→        } catch (error) {
   853→          logger.error('Failed to delete conversation on server', { error: String(error) });
   854→        }
   855→      },
   856→
   857→      clearConversations: () =>
   858→        set({ conversations: [], currentConversationId: null }),
   859→
   860→      syncToServer: async () => {
   861→        // Conversations are synced immediately on each action
   862→        set({ lastSyncedAt: new Date(), pendingSync: false });
   863→      },
   864→
   865→      loadFromServer: async () => {
   866→        try {
   867→          const response = await fetch('/api/conversations?limit=50');
   868→          if (response.ok) {
   869→            const conversations = await response.json();
   870→            set({
   871→              conversations: conversations.map((c: {
   872→                id: string;
   873→                title: string;
   874→                maestroId: string;
   875→                createdAt: string;
   876→                updatedAt: string;
   877→                lastMessage?: string;
   878→              }) => ({
   879→                ...c,
   880→                messages: [], // Messages are loaded on-demand
   881→                createdAt: new Date(c.createdAt),
   882→                updatedAt: new Date(c.updatedAt),
   883→              })),
   884→              lastSyncedAt: new Date(),
   885→              pendingSync: false,
   886→            });
   887→          }
   888→        } catch (error) {
   889→          logger.error('Conversations load failed', { error: String(error) });
   890→        }
   891→      },
   892→    })
   893→);
