   900→  insight: string;
   901→  maestroId?: string;
   902→  subject?: string;
   903→  confidence: number;
   904→  occurrences: number;
   905→  createdAt: Date;
   906→  updatedAt: Date;
   907→}
   908→
   909→interface LearningsState {
   910→  learnings: Learning[];
   911→  lastSyncedAt: Date | null;
   912→  // Actions
   913→  addLearning: (learning: Omit<Learning, 'id' | 'occurrences' | 'createdAt' | 'updatedAt'>) => Promise<void>;
   914→  removeLearning: (id: string) => Promise<void>;
   915→  getLearningsByCategory: (category: Learning['category']) => Learning[];
   916→  // Sync
   917→  loadFromServer: () => Promise<void>;
   918→}
