   920→export const useLearningsStore = create<LearningsState>()(
   921→  (set, get) => ({
   922→      learnings: [],
   923→      lastSyncedAt: null,
   924→
   925→      addLearning: async (learning) => {
   926→        try {
   927→          const response = await fetch('/api/learnings', {
   928→            method: 'POST',
   929→            headers: { 'Content-Type': 'application/json' },
   930→            body: JSON.stringify(learning),
   931→          });
   932→
   933→          if (response.ok) {
   934→            const serverLearning = await response.json();
   935→            set((state) => {
   936→              // Check if this was a reinforcement
   937→              if (serverLearning.reinforced) {
   938→                return {
   939→                  learnings: state.learnings.map((l) =>
   940→                    l.id === serverLearning.id
   941→                      ? { ...l, confidence: serverLearning.confidence, occurrences: serverLearning.occurrences }
   942→                      : l
   943→                  ),
   944→                };
   945→              }
   946→              // New learning
   947→              return {
   948→                learnings: [
   949→                  {
   950→                    ...serverLearning,
   951→                    createdAt: new Date(serverLearning.createdAt),
   952→                    updatedAt: new Date(serverLearning.updatedAt),
   953→                  },
   954→                  ...state.learnings,
   955→                ],
   956→              };
   957→            });
   958→          }
   959→        } catch (error) {
   960→          logger.error('Failed to add learning', { error: String(error) });
