   966→          learnings: state.learnings.filter((l) => l.id !== id),
   967→        }));
   968→
   969→        try {
   970→          await fetch(`/api/learnings?id=${id}`, { method: 'DELETE' });
   971→        } catch (error) {
   972→          logger.error('Failed to remove learning', { error: String(error) });
   973→        }
   974→      },
   975→
   976→      getLearningsByCategory: (category) => {
   977→        return get().learnings.filter((l) => l.category === category);
   978→      },
   979→
   980→      loadFromServer: async () => {
   981→        try {
   982→          const response = await fetch('/api/learnings');
   983→          if (response.ok) {
   984→            const learnings = await response.json();
   985→            set({
   986→              learnings: learnings.map((l: Learning & { createdAt: string; updatedAt: string }) => ({
   987→                ...l,
   988→                createdAt: new Date(l.createdAt),
   989→                updatedAt: new Date(l.updatedAt),
   990→              })),
   991→              lastSyncedAt: new Date(),
   992→            });
   993→          }
   994→        } catch (error) {
   995→          logger.error('Learnings load failed', { error: String(error) });
   996→        }
   997→      },
   998→    })
   999→);
