  1139→          return {
  1140→            events: [
  1141→              ...state.events,
  1142→              {
  1143→                ...event,
  1144→                id: crypto.randomUUID(),
  1145→                completed: false,
  1146→                maestroSuggested: maestroId,
  1147→              },
  1148→            ],
  1149→          };
  1150→        }),
  1151→
  1152→      updateEvent: (id, updates) =>
  1153→        set((state) => ({
  1154→          events: state.events.map((e) =>
  1155→            e.id === id ? { ...e, ...updates } : e
  1156→          ),
  1157→        })),
  1158→
  1159→      deleteEvent: (id) =>
  1160→        set((state) => ({
  1161→          events: state.events.filter((e) => e.id !== id),
  1162→        })),
  1163→
  1164→      toggleCompleted: (id) =>
  1165→        set((state) => ({
