  1167→            e.id === id ? { ...e, completed: !e.completed } : e
  1168→          ),
  1169→        })),
  1170→
  1171→      getUpcomingEvents: (days) => {
  1172→        const now = new Date();
  1173→        const future = new Date(now.getTime() + days * 24 * 60 * 60 * 1000);
  1174→        return get()
  1175→          .events.filter(
  1176→            (e) => !e.completed && new Date(e.date) >= now && new Date(e.date) <= future
  1177→          )
  1178→          .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  1179→      },
  1180→
  1181→      getEventsBySubject: (subject) => {
  1182→        return get().events.filter(
  1183→          (e) => e.subject.toLowerCase() === subject.toLowerCase()
  1184→        );
  1185→      },
  1186→
  1187→      getSuggestedMaestri: () => {
  1188→        const upcoming = get().getUpcomingEvents(7);
  1189→        const suggestions: Map<string, { count: number; nearestDays: number; types: Set<string> }> = new Map();
  1190→
  1191→        const now = new Date();
  1192→        upcoming.forEach((event) => {
  1193→          const maestroId = event.maestroSuggested;
  1194→          if (!maestroId) return;
  1195→
  1196→          const daysUntil = Math.ceil(
  1197→            (new Date(event.date).getTime() - now.getTime()) / (24 * 60 * 60 * 1000)
  1198→          );
  1199→
  1200→          if (suggestions.has(maestroId)) {
  1201→            const existing = suggestions.get(maestroId)!;
  1202→            existing.count++;
  1203→            existing.nearestDays = Math.min(existing.nearestDays, daysUntil);
  1204→            existing.types.add(event.type);
  1205→          } else {
  1206→            suggestions.set(maestroId, {
  1207→              count: 1,
  1208→              nearestDays: daysUntil,
  1209→              types: new Set([event.type]),
  1210→            });
  1211→          }
  1212→        });
  1213→
  1214→        return Array.from(suggestions.entries())
  1215→          .map(([maestroId, data]) => {
  1216→            let priority: 'high' | 'medium' | 'low' = 'low';
  1217→            let reason = '';
  1218→
  1219→            if (data.nearestDays <= 1) {
  1220→              priority = 'high';
  1221→              reason = data.types.has('exam') || data.types.has('test')
  1222→                ? 'Test tomorrow - review now!'
  1223→                : 'Event tomorrow';
  1224→            } else if (data.nearestDays <= 3) {
  1225→              priority = 'high';
  1226→              reason = `${data.count} event${data.count > 1 ? 's' : ''} in ${data.nearestDays} days`;
  1227→            } else if (data.nearestDays <= 5) {
  1228→              priority = 'medium';
  1229→              reason = `Prepare for upcoming ${Array.from(data.types).join('/')}`;
  1230→            } else {
  1231→              priority = 'low';
  1232→              reason = `${data.count} event${data.count > 1 ? 's' : ''} this week`;
  1233→            }
  1234→
  1235→            return { maestroId, reason, priority };
  1236→          })
  1237→          .sort((a, b) => {
  1238→            const priorityOrder = { high: 0, medium: 1, low: 2 };
  1239→            return priorityOrder[a.priority] - priorityOrder[b.priority];
  1240→          });
  1241→      },
  1242→    })
